VALUES
  ('bookkeeper-moex-00179', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據營利事業所得稅查核準則有關捐贈認列費用之規定，下列敘述何者正確？', '["營利事業指定對特定學校法人或私立學校之捐款得列為費用，但以不超過其所得額30%為限", "營利事業依運動產業發展條例第26條之二第三項規定對經中央主管機關專案核准之重點職業或業 餘運動業，及經中央主管機關公告之重點運動賽事主辦單位之捐贈，得按捐贈金額之150%，自所得額 中減除", "營利事業依政治獻金法第19條第2項規定，對政黨、政治團體及擬參選人之捐贈得列為費用，以 不超過所得額20%為限，其總額並不得超過新臺幣250萬元", "營利事業為協助國防建設、慰勞軍隊、對各級政府、及經財政部專案核准之捐贈，以新臺幣 2,000 萬元為限，自所得額中減除"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00180', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據營利事業所得稅查核準則之規定，旅費支出，應提示詳載逐日前往地點、訪洽對象及內容等之出 差報告單及相關文件，足資證明與營業有關者，憑以認定；其未能提出者，應不予認定。其中有關搭 乘各種交通工具之交通費核銷憑證，下列何種情形准以經手人（即出差人）之證明為憑，核實認定？', '["租賃之包車費", "搭乘國內航線之飛機", "搭乘國際航線之飛機", "搭乘高速鐵路當日往返"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00181', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '我國現行營利事業所得稅查核準則，有關營利事業呆帳損失之列支以及備抵呆帳之提列，下列敘述何 者正確？', '["債務人倒閉、逃匿、重整、和解或破產之宣告，或其他原因，致債權之一部或全部不能收回者，視 為實際發生呆帳損失，並應於發生當年度沖抵備抵呆帳", "債權中有逾期一年，經催收後，未經收取本金或利息者，視為實際發生呆帳損失，並應於發生當年 度沖抵備抵呆帳", "提列備抵呆帳，以應收帳款及應收票據為限，並包括已貼現之票據", "備抵呆帳餘額，最高不得超過應收帳款及應收票據餘額之3%；其為金融業者，則以其債權餘額估 列之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00182', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據現行營利事業所得稅查核準則之規定，下列營利事業所繳納之稅捐，何者得列為當期之費用？', '["公司進口貨物所繳納之關稅", "上一年度所繳納之營利事業所得稅", "公司名下所有之廠房、辦公室所繳納的房屋稅與地價稅", "公司購買土地、房屋所繳納之契稅、印花稅等"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00183', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依據營利事業所得稅查核準則，下列何者應列為「非營業收入」？', '["繳納的稅捐原以費用列帳者，如於繳納年度收到退稅款時", "繳納的稅捐原以費用列帳者，如於以後年度始收到退稅款者", "繳納外銷品進口原料應以成本列帳的稅捐，其成品於當年度外銷並收到海關退稅款者", "繳納外銷品進口原料應以成本列帳的稅捐，其成品於次年度外銷並收到海關退稅款者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00184', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依據營利事業所得稅查核準則，有關營利事業列報利息費用應注意事項，下列敘述何者錯誤？', '["獨資資本主及合夥組織合夥人所借貸之款項，均應以資本主往來論，不得列支利息", "進貨借款所支付之利息，應併入進貨成本計算", "支付個人的利息，如經取得個人出具的收據並依法辦理扣繳所得稅款，可核實認定", "購買供營業使用房屋、土地的借款利息，應列為資本支出。經辦妥過戶手續或交付使用後之借款利 息，可作費用列支"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00185', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依據營利事業所得稅查核準則，下列支出不屬於可核實認定的費用或損失？', '["因業務需要免費發給員工之工作服", "沒收保證金經取得證明文據者", "購置體育器具及本身舉辦員工體育活動所支付之各項費用", "指定對特定學校法人或私立學校之捐款"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00186', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依據營利事業所得稅查核準則，有關帳簿憑證的查核，下列敘述何者錯誤？', '["營利事業有漏報營業收入情事，經稽徵機關就該漏報部分按同業利潤標準核定其所得額者，其核定 之所得額，以不超過當年度全部營業收入淨額依同業利潤標準核定之所得額為限", "營利事業未提示有關各種證明所得額之帳簿文據，經稽徵機關就營業收入淨額按同業利潤標準核定 其所得額者，如有非營業收益或損失，應依法合併計課或核實減除", "營利事業如在規定送交調查時間以內申請延期提示帳簿文據者，稽徵機關應予受理。但延長的期限 最長不得超過一個月，並以一次為限", "營利事業當年度關係所得額之全部或一部的原始憑證，因遭受不可抗力災害以致滅失者，該滅失憑 證所屬期間之所得額，稽徵機關得依該事業前三個年度經稽徵機關核定純益率之平均數核定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00187', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依據營利事業所得稅查核準則，有關收入的查核，下列敘述何者正確？', '["營利事業國外進、銷貨，其入帳匯率與結匯匯率變動所產生之收益，應調整其外銷收入或進料、進 貨成本", "營利事業銷售貨物或勞務，如有隨銷售附贈禮券、獎勵積點或保固服務等，該附贈部分相對應的收 入認列應予以遞延", "外銷貨物應列為外銷貨物報關日所屬會計年度之銷貨收入處理", "營利事業分期付款之銷貨，其當期損益得依全部毛利法、毛利百分比法與普通銷貨法擇一計算。所 有產品同期分期付款銷貨損益均應採用同一計算方式，不得中途變更"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00188', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '根據加值型及非加值型營業稅法之規定，下列何種情形非屬營業稅課徵範圍？', '["營業人解散時，將餘存貨物分配予股東", "外銷貨物", "進口貨物", "由國外進入科學園區內之園區事業的保稅貨物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00189', 'bookkeeper', 'bookkeeper-moex-113-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列有關銷售貨物或勞務營業稅徵免之敘述，何者正確？', '["與外銷有關之勞務，或在國內提供而在國外使用之勞務，非屬我國營業稅課徵範圍，免徵營業稅", "銷售予免稅出口區外銷廠商之生產設備，適用零稅率，其進項稅額得申請扣抵及退稅", "依法設立之免稅商店銷售與過境或出境旅客之貨物，適用免稅優惠，無銷項稅額，亦不得申請進項 稅額扣抵及退稅", "醫院、診所、療養院提供之醫療勞務、藥品、病房之住宿及膳食，屬一般銷售貨物及勞務，應課徵 營業稅，但若為財團法人者，可申請減半徵收"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:19+00:00", "source_pdf_sha1": "1b22e5321747", "answer_pdf_sha1": "27d2bd6acd46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "602", "s": "1404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
